+static Value *simplifyReductionOperand(Value *Arg, bool CanReorderLanes) {
+  Value *Src;
+  if (match(Arg, m_Shuffle(m_Value(Src), m_Undef(), m_Mask())) &&
+      (CanReorderLanes || cast<ShuffleVectorInst>(Arg)->isIdentityWithPadding()))
+    return Src;
+  return nullptr;
+}
