+Instruction *InstCombinerImpl::visitCallInst(CallInst &CI) {
+  IntrinsicInst *II = dyn_cast<IntrinsicInst>(&CI);
+  if (!II)
+    return visitCallBase(CI);
+
+  Intrinsic::ID IID = II->getIntrinsicID();
+  switch (IID) {
+  case Intrinsic::umax: {
+    Type *Ty = II->getType();
+    if (Ty->isIntegerTy()) {
+      auto MatchUMaxShlAdd = [&](Value *ShlV, Value *AddV, Value *&X,
+                                 Value *&Shl) -> bool {
+        Value *ShlX;
+        const APInt *ShAmt;
+        if (!match(ShlV, m_NUWShl(m_Value(ShlX), m_APInt(ShAmt))) ||
+            !ShAmt->isOne())
+          return false;
+
+        Value *AddX;
+        const APInt *C;
+        if (!(match(AddV, m_Add(m_Value(AddX), m_APInt(C))) ||
+              match(AddV, m_Add(m_APInt(C), m_Value(AddX)))))
+          return false;
+
+        if (!C->isOne() || AddX != ShlX)
+          return false;
+
+        X = ShlX;
+        Shl = ShlV;
+        return true;
+      };
+
+      Value *X = nullptr;
+      Value *Shl = nullptr;
+      Value *A = II->getArgOperand(0);
+      Value *B = II->getArgOperand(1);
+      if (MatchUMaxShlAdd(A, B, X, Shl) || MatchUMaxShlAdd(B, A, X, Shl)) {
+        Value *Eq = Builder.CreateICmpEQ(X, ConstantInt::get(Ty, 0));
+        Value *Res = Builder.CreateSelect(Eq, ConstantInt::get(Ty, 1), Shl);
+        return replaceInstUsesWith(CI, Res);
+      }
+    }
+    break;
+  }
+  case Intrinsic::vector_reduce_add:
+  case Intrinsic::vector_reduce_or: {
+    Value *Arg = II->getArgOperand(0);
+    if (Value *NewOp =
+            simplifyReductionOperand(Arg, /*CanReorderLanes=*/true)) {
+      replaceUse(II->getOperandUse(0), NewOp);
+      return II;
+    }
     [[fallthrough]];
   }
   case Intrinsic::vector_reduce_xor: {
@@ -3768,6 +3908,7 @@ Instruction *InstCombinerImpl::visitCallInst(CallInst &CI) {
   return visitCallBase(*II);
 }

